#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int odds = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x & 1) odds++;
        }
        int evens = N - odds;
        int ans;
        if (odds % 2 == 0) ans = odds / 2 < evens ? odds / 2 : evens;
        else ans = evens;
        printf("%d\n", ans);
    }
    return 0;
}

