#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    if not data:
        return
    t = data[0]
    idx = 1
    out_lines = []
    for _ in range(t):
        n = data[idx]
        idx += 1
        odds = 0
        for i in range(n):
            if data[idx + i] & 1:
                odds += 1
        idx += n
        evens = n - odds
        if odds % 2 == 0:
            out_lines.append(str(min(odds // 2, evens)))
        else:
            out_lines.append(str(evens))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

